725	func efficacyFingerprint(projectRoot string) (string, error) {
726		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
727		beads, err := store.ReadAll()
728		if err != nil {
729			return "", err
730		}
731		var evidenceCount int
732		var maxEvidenceUnix int64
733		for _, b := range beads {
734			if b.Status != bead.StatusClosed {
735				continue
736			}
737			events, err := store.Events(b.ID)
738			if err != nil {
739				return "", err
740			}
741			for _, event := range events {
742				if event.Kind != "routing" && event.Kind != "cost" {
743					continue
744				}
745				evidenceCount++
746				if ts := event.CreatedAt.UnixNano(); ts > maxEvidenceUnix {
747					maxEvidenceUnix = ts
748				}
749			}
750		}
751		return fmt.Sprintf("%s|filters=none|max_event_sequence=%d|max_created_at=%d", projectRoot, evidenceCount, maxEvidenceUnix), nil
752	}
