754	func buildEfficacySnapshot(projectRoot string) (string, efficacySnapshot, error) {
755		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
756		beads, err := store.ReadAll()
757		if err != nil {
758			return "", efficacySnapshot{}, err
759		}
760	
761		var attempts []evidenceAttempt
762		var evidenceCount int
763		var maxEvidenceUnix int64
764		for _, b := range beads {
765			if b.Status != bead.StatusClosed {
766				continue
767			}
768			events, err := store.Events(b.ID)
769			if err != nil {
770				return "", efficacySnapshot{}, err
771			}
772			attempts = append(attempts, attemptsFromEvidence(b.ID, events, &evidenceCount, &maxEvidenceUnix)...)
773		}
774	
775		key := fmt.Sprintf("%s|filters=none|max_event_sequence=%d|max_created_at=%d", projectRoot, evidenceCount, maxEvidenceUnix)
776		grouped := map[string][]evidenceAttempt{}
777		for _, attempt := range attempts {
778			grouped[attempt.RowKey] = append(grouped[attempt.RowKey], attempt)
779		}
780	
781		rows := make([]*EfficacyRow, 0, len(grouped))
782		attemptDetails := map[string][]*EfficacyAttempt{}
783		for rowKey, group := range grouped {
784			sort.Slice(group, func(i, j int) bool { return group[i].CreatedAt.After(group[j].CreatedAt) })
785			attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
786			var inputTokens, outputTokens, durations []int
787			var costs []float64
788			var successes int
789			for _, attempt := range group {
790				if attempt.Outcome == "succeeded" {
791					successes++
792				}
793				inputTokens = append(inputTokens, attempt.InputTokens)
794				outputTokens = append(outputTokens, attempt.OutputTokens)
795				durations = append(durations, attempt.DurationMs)
796				if attempt.CostUsd != nil {
797					costs = append(costs, *attempt.CostUsd)
798				}
799				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
800					BeadID:            attempt.BeadID,
801					Outcome:           attempt.Outcome,
802					DurationMs:        attempt.DurationMs,
803					CostUsd:           attempt.CostUsd,
804					EvidenceBundleURL: attempt.EvidencePath,
805				})
806			}
807			parts := strings.Split(rowKey, "|")
808			row := &EfficacyRow{
809				RowKey:             rowKey,
810				Harness:            parts[0],
811				Provider:           parts[1],
812				Model:              parts[2],
813				Attempts:           len(group),
814				Successes:          successes,
815				SuccessRate:        float64(successes) / float64(len(group)),
816				MedianInputTokens:  medianInt(inputTokens),
817				MedianOutputTokens: medianInt(outputTokens),
818				MedianDurationMs:   medianInt(durations),
819				MedianCostUsd:      medianFloatPtr(costs),
820			}
821			if row.SuccessRate < efficacyWarningFloor {
822				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
823			}
824			rows = append(rows, row)
825		}
826		sort.Slice(rows, func(i, j int) bool {
827			if rows[i].SuccessRate != rows[j].SuccessRate {
828				return rows[i].SuccessRate > rows[j].SuccessRate
829			}
830			return rows[i].RowKey < rows[j].RowKey
831		})
832	
833		return key, efficacySnapshot{key: key, rows: rows, attempts: attemptDetails}, nil
834	}
