836	func attemptsFromEvidence(beadID string, events []bead.BeadEvent, evidenceCount *int, maxEvidenceUnix *int64) []evidenceAttempt {
837		var out []evidenceAttempt
838		var lastRouting routingEvidence
839		for i, event := range events {
840			if event.Kind != "routing" && event.Kind != "cost" {
841				continue
842			}
843			(*evidenceCount)++
844			if ts := event.CreatedAt.UnixNano(); ts > *maxEvidenceUnix {
845				*maxEvidenceUnix = ts
846			}
847	
848			switch event.Kind {
849			case "routing":
850				lastRouting = parseRoutingEvidence(event.Body)
851				if lastRouting.Provider == "" && lastRouting.Model == "" {
852					continue
853				}
854			case "cost":
855				attempt := parseCostEvidence(beadID, event, i, lastRouting)
856				out = append(out, attempt)
857			}
858		}
859		if len(out) == 0 && (lastRouting.Provider != "" || lastRouting.Model != "") {
860			out = append(out, newRoutingOnlyAttempt(beadID, len(events), lastRouting))
861		}
862		return out
863	}
